rule.definition:
/* This expression is invalid and must be fixed before use
 a!localVariables(
  local!startDate: a!defaultValue(ri!startDate, today()),
  local!endDate: a!defaultValue(ri!endDate, today()),
  local!holidays: if(isnull(ri!publicHolidays), {}, ri!publicHolidays),

  local!totalDays: if(
    local!endDate >= local!startDate,
    tointeger(local!endDate - local!startDate) + 1,
    0
  ),

  local!allDatesInRange: if(
    local!totalDays > 0,
    a!forEach(
      items: enumerate(local!totalDays) - 1,
      expression: a!addDateTime(
        startDateTime: local!startDate,
        days: fv!item
      )
    ),
    {}
  ),

  local!workingDaysCount: length(
    where(
      a!forEach(
        items: local!allDatesInRange,
        expression: and(
          not(or(dayofweek(fv!item) = 1, dayofweek(fv!item) = 7)),
          not(contains(local!holidays, fv!item))
        )
      )
    )
  ),

  local!workingDaysCount
)
 */
